import { TZDateMini } from '@date-fns/tz';
import { endOfDay, startOfDay } from 'date-fns';
import type { DebouncedFunc } from 'lodash-es';
import type { Dispatch, RefObject } from 'react';
import type { StoreApi } from 'zustand';

import { getTimezone } from '@dynatrace-sdk/user-preferences';

import { getTimeframeFromCalendarSelection } from './calendar.js';
import { focusElementWithRetry } from '../../../../forms/date-time-picker/utils/focusDateTimeInput.js';
import type { FormFieldMessagesReducerAction } from '../../../../forms/forms-core/state/formfield-messages-state-reducer.js';
import {
  removePrecision,
  removePrecisionFromTimeFrame,
} from '../../../../forms/forms-core/time/timeParser.js';
import type { TimeRangePickerRef } from '../../../../forms/shared-types.js';
import { type Timeframe } from '../../../types/time.js';
import {
  isFullTimeframe,
  isTimeValue,
  mergeRangeValue,
} from '../../helpers.js';
import { validate } from '../../validation.js';
import type { ValidateOptions } from '../../validation.js';
import type {
  TimeframeSelectorState,
  TimeframeSelectorStoreActions,
} from '../timeframeSelector.types.js';

/**
 * Handles setting the TimeframeSelector timeframe value.
 * Validates the input, calls onChange callback, closes the selector,
 * and updates all related state (selector, calendar, dateTimePicker).
 * @internal
 */
function handleTimeframeSelectorTimeframeChange(
  inputValue: Timeframe | null,
  state: TimeframeSelectorState,
  isControlled: boolean,
  timeframeSelectorRef: RefObject<TimeRangePickerRef>,
  formFieldMessagesDispatch?: Dispatch<FormFieldMessagesReducerAction>,
  onChangeProp?: (value: Timeframe | null) => void,
  errorMessages?: ValidateOptions['errorMessages'],
): Partial<TimeframeSelectorState> {
  const timeframeWithPrecision =
    removePrecisionFromTimeFrame(inputValue, state.precision) ?? null;

  const value = isFullTimeframe(timeframeWithPrecision)
    ? timeframeWithPrecision
    : null;

  onChangeProp?.(value);
  timeframeSelectorRef.current?.close();

  if (isControlled) {
    return state;
  }

  const error = validate(timeframeWithPrecision, state.min, state.max, {
    formMessageDispatch: formFieldMessagesDispatch,
    formerError: state.timeframeSelectorError,
    precision: state.precision,
    showError: false,
    checkOrder: true,
    ref: timeframeSelectorRef,
    expectedFormat: state.formatString,
    valueMode: 'timeframeSelector',
    required: state.required,
    errorMessages,
  });

  return {
    timeframeSelectorTimeframe: value,
    calendarValue: value ?? timeframeWithPrecision,
    dateTimeRangePickerTimeframe: value ?? timeframeWithPrecision,
    timeframeSelectorError: error,
    calendarError: error,
    dateTimeRangePickerError: error,
  };
}

/**
 * Handles setting the previous timeframe value.
 * Used for tracking the last valid timeframe before changes.
 * @internal
 */
function handlePreviousTimeframeChange(
  value: Timeframe | null,
): Partial<TimeframeSelectorState> {
  return {
    referenceTimeframe: value,
  };
}

function isFullDayTimeframe(
  timeframe: Timeframe,
  state: TimeframeSelectorState,
): boolean {
  const timeZone = getTimezone();
  const to = new TZDateMini(timeframe.to.absoluteDate, timeZone);
  const from = new TZDateMini(timeframe.from.absoluteDate, timeZone);

  const isToAtEndOfDay =
    removePrecision(endOfDay(to).toISOString(), state.precision) ===
    removePrecision(timeframe.to.absoluteDate, state.precision);
  const isToAtMax = state.max?.absoluteDate === to.toISOString();

  const isFromAtStartOfDay =
    removePrecision(startOfDay(from).toISOString(), state.precision) ===
    removePrecision(timeframe.from.absoluteDate, state.precision);
  const isFromAtMin = state.min?.absoluteDate === from.toISOString();

  return Boolean(
    (isToAtEndOfDay || isToAtMax) && (isFromAtStartOfDay || isFromAtMin),
  );
}

/**
 * Creates actions for the TimeframeSelector store using the slice action handlers.
 * @internal
 */
export function getTimeframeSelectorActions(
  isControlled: boolean,
  timeframeSelectorRef: RefObject<TimeRangePickerRef>,
  formFieldMessagesDispatch?: Dispatch<FormFieldMessagesReducerAction>,
  onChangeProp?: ((value: Timeframe | null) => void) | undefined,
  debouncedOnChangeRef?: RefObject<
    DebouncedFunc<(timeframe: Timeframe | null) => void>
  >,
  errorMessages?: ValidateOptions['errorMessages'],
) {
  const actions = (
    set: StoreApi<
      TimeframeSelectorState & TimeframeSelectorStoreActions
    >['setState'],
  ): TimeframeSelectorStoreActions => {
    return {
      setCalendarValue: (inputValue) => {
        set((state) => {
          const calendarValue = getTimeframeFromCalendarSelection(
            inputValue,
            state,
          );

          if (isFullTimeframe(calendarValue)) {
            state.dateTimeRangePickerRef?.current?.close();
            const isFullDay = isFullDayTimeframe(calendarValue, state);

            focusElementWithRetry(
              () =>
                state.dateTimeFromRef.current?.spinButtonHandlers.get('hour')
                  ?.element.current,
              state.dateTimeFromRef,
            );

            return {
              calendarValue,
              dateTimeRangePickerTimeframe: calendarValue,
              isFullDay,
            };
          }

          return { calendarValue, isFullDay: false };
        });
      },
      setDateTimeRangePickerTimeframe: (value) => {
        return set((state) => {
          // Full clear: null resets both fields to null and errors to undefined
          if (value === null) {
            return {
              dateTimeRangePickerTimeframe: null,
              calendarValue: null,
              dateTimeRangePickerError: undefined,
              calendarError: undefined,
            };
          }

          const merged = mergeRangeValue(
            state.dateTimeRangePickerTimeframe,
            value,
          );

          const timeframeWithPrecision =
            removePrecisionFromTimeFrame(merged, state.precision) ?? null;

          const isPartialFrom =
            isTimeValue(merged.from) && merged.from.absoluteDate === '';
          const isPartialTo =
            isTimeValue(merged.to) && merged.to.absoluteDate === '';

          // For partial values while editing we trigger onChange with '' to inform
          // the user that the current value is invalid, but not empty.
          if (isPartialFrom || isPartialTo) {
            const errorKey = validate(
              timeframeWithPrecision,
              state.min,
              state.max,
              {
                formerError: state.dateTimeRangePickerError,
                precision: state.precision,
                showError: false,
                checkOrder: true,
                ref: state.dateTimeRangePickerRef,
                expectedFormat: state.formatString,
                valueMode: 'timeframeSelector',
                required: state.required,
                errorMessages,
              },
            );

            const calendarValue = {
              from: isPartialFrom ? null : timeframeWithPrecision?.from ?? null,
              to: isPartialTo ? null : timeframeWithPrecision?.to ?? null,
            };

            return {
              dateTimeRangePickerTimeframe: timeframeWithPrecision,
              calendarValue,
              calendarError: errorKey,
              dateTimeRangePickerError: errorKey,
            };
          }

          const dateTimeRangePickerError = validate(
            timeframeWithPrecision,
            state.min,
            state.max,
            {
              formerError: state.dateTimeRangePickerError,
              precision: state.precision,
              showError: false,
              checkOrder: true,
              ref: state.dateTimeRangePickerRef,
              expectedFormat: state.formatString,
              valueMode: 'timeframeSelector',
              required: state.required,
              errorMessages,
            },
          );

          return {
            dateTimeRangePickerTimeframe: timeframeWithPrecision,
            calendarValue: timeframeWithPrecision,
            calendarError: dateTimeRangePickerError,
            dateTimeRangePickerError,
          };
        });
      },
      setTimeframeSelectorTimeframe: (inputValue) => {
        debouncedOnChangeRef?.current?.cancel();
        return set((state) =>
          handleTimeframeSelectorTimeframeChange(
            inputValue,
            state,
            isControlled,
            timeframeSelectorRef,
            formFieldMessagesDispatch,
            onChangeProp,
            errorMessages,
          ),
        );
      },
      setReferenceTimeframe: (value) => {
        set(() => handlePreviousTimeframeChange(value));
      },
      setStepperValue: (value) => {
        set(() => {
          debouncedOnChangeRef?.current?.(value);
          return {
            timeframeSelectorTimeframe: value,
            calendarValue: value,
            dateTimeRangePickerTimeframe: value,
          };
        });
      },
      clearCalendarValue: () => {
        set((state) => {
          if (
            !state.calendarValue ||
            (state.calendarValue.from && state.calendarValue.to)
          ) {
            return state;
          }

          if (
            state.dateTimeRangePickerTimeframe?.from &&
            state.dateTimeRangePickerTimeframe?.to
          ) {
            return { calendarValue: state.dateTimeRangePickerTimeframe };
          }

          // in case of a partial value, we want to clear the calendar selection entirely to avoid confusion
          return { calendarValue: null };
        });
      },
    };
  };

  return actions;
}
